CREATE OR REPLACE FUNCTION fpa_mobile_get_active_acc_no ( as_memno char ) RETURNS varchar AS $body$
DECLARE

ls_bank_acc_no  sc_mobile_regis.bank_acc_no%type;


BEGIN

    begin 
      SELECT sc_mobile_regis.bank_acc_no  into STRICT  ls_bank_acc_no
      FROM sc_mobile_regis  
      WHERE ( sc_mobile_regis.close_status = '0' ) AND ( sc_mobile_regis.membership_no = as_memno );

    exception
    when too_many_rows then return '';
    when no_data_found then return '';
    when others then CALL spa_dberror('FPA_MOBILE_GET_ACTIVE_ACC_NO');
    end;

  return ls_bank_acc_no;

exception when others then return 0;
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
